const items = $input.all();
const pagar = items[0]?.json || {};
const receber = items[1]?.json || {};

const hoje = new Date();
const seg = new Date(hoje);
seg.setDate(hoje.getDate() - hoje.getDay() + 1);
const dom = new Date(seg);
dom.setDate(seg.getDate() + 6);

const mesesAbrev = ['jan','fev','mar','abr','mai','jun','jul','ago','set','out','nov','dez'];
const fmtDate = (d) => {
  const parts = d.split('-');
  return `${parseInt(parts[2])}/${mesesAbrev[parseInt(parts[1])-1]}`;
};
const fmtParcela = (num, total) => `${parseInt(num)}/${parseInt(total)}`;
const fmtMoney = (v) => 'R$ ' + Number(v).toLocaleString('pt-BR', {minimumFractionDigits: 2, maximumFractionDigits: 2});
const fmtDateRange = (d) => `${String(d.getDate()).padStart(2,'0')}/${String(d.getMonth()+1).padStart(2,'0')}/${d.getFullYear()}`;
const pad2 = (n) => String(n).padStart(2,'0');

const semanaIni = `${seg.getFullYear()}-${pad2(seg.getMonth()+1)}-${pad2(seg.getDate())}`;
const semanaFim = `${dom.getFullYear()}-${pad2(dom.getMonth()+1)}-${pad2(dom.getDate())}`;

// Mês atual
const mesAtualIni = `${hoje.getFullYear()}-${pad2(hoje.getMonth()+1)}-01`;
const ultimoDiaMesAtual = new Date(hoje.getFullYear(), hoje.getMonth()+1, 0).getDate();
const mesAtualFim = `${hoje.getFullYear()}-${pad2(hoje.getMonth()+1)}-${pad2(ultimoDiaMesAtual)}`;
const nomeMesAtual = hoje.toLocaleString('pt-BR', {month: 'long', year: 'numeric'});

// Próximo mês
const proxMes = new Date(hoje.getFullYear(), hoje.getMonth()+1, 1);
const proxMesIni = `${proxMes.getFullYear()}-${pad2(proxMes.getMonth()+1)}-01`;
const ultimoDiaProxMes = new Date(proxMes.getFullYear(), proxMes.getMonth()+1, 0).getDate();
const proxMesFim = `${proxMes.getFullYear()}-${pad2(proxMes.getMonth()+1)}-${pad2(ultimoDiaProxMes)}`;
const nomeProxMes = proxMes.toLocaleString('pt-BR', {month: 'long', year: 'numeric'});

const allPagar = pagar.duplicatas || [];
const allReceber = receber.duplicatas || [];

// Filtros
const pagarSemana = allPagar.filter(d => d.dupVencimento >= semanaIni && d.dupVencimento <= semanaFim);
const receberSemana = allReceber.filter(d => d.dupVencimento >= semanaIni && d.dupVencimento <= semanaFim);
const vencidas = allPagar.filter(d => d.status === 'overdue');

const pagarMesAtual = allPagar.filter(d => d.dupVencimento >= mesAtualIni && d.dupVencimento <= mesAtualFim);
const receberMesAtual = allReceber.filter(d => d.dupVencimento >= mesAtualIni && d.dupVencimento <= mesAtualFim);
const pagarProxMes = allPagar.filter(d => d.dupVencimento >= proxMesIni && d.dupVencimento <= proxMesFim);
const receberProxMes = allReceber.filter(d => d.dupVencimento >= proxMesIni && d.dupVencimento <= proxMesFim);

const totalArr = (arr) => arr.reduce((s,d) => s + d.dupValor, 0);

// Helper: tabela pagar consolidada por fornecedor
const tabelaPagarConsolidada = (lista, corTitulo, titulo) => {
  let h = `<div style=\"padding: 15px;\">`;
  h += `<h2 style=\"color: ${corTitulo}; font-size: 16px; border-bottom: 2px solid ${corTitulo}; padding-bottom: 5px;\">💰 ${titulo}</h2>`;
  if (lista.length === 0) {
    h += `<p style=\"color: #888;\">Nenhum registro.</p>`;
  } else {
    const grupos = {};
    for (const d of lista) {
      const nome = d.emitenteNomeAbreviado || d.emitenteNome;
      if (!grupos[nome]) grupos[nome] = { nfs: new Set(), total: 0, items: [] };
      grupos[nome].nfs.add(d.nfNumero);
      grupos[nome].total += d.dupValor;
      grupos[nome].items.push(d);
    }
    const sorted = Object.entries(grupos).sort((a,b) => b[1].total - a[1].total);
    h += `<table style=\"width:100%; border-collapse: collapse; font-size: 13px;\">`;
    h += `<tr style=\"background: #f8f8f8;\"><th style=\"padding:8px; text-align:left; border-bottom:2px solid #ddd;\">Fornecedor</th><th style=\"padding:8px; text-align:center; border-bottom:2px solid #ddd;\">NFs</th><th style=\"padding:8px; text-align:right; border-bottom:2px solid #ddd;\">Total</th></tr>`;
    for (const [nome, g] of sorted) {
      const nfList = Array.from(g.nfs).join(', ');
      h += `<tr><td style=\"padding:6px 8px; border-bottom:1px solid #eee;\">${nome}<br><span style=\"font-size:11px; color:#888;\">(NFs: ${nfList})</span></td><td style=\"padding:6px 8px; border-bottom:1px solid #eee; text-align:center;\">${g.nfs.size}</td><td style=\"padding:6px 8px; border-bottom:1px solid #eee; text-align:right; font-weight:bold;\">${fmtMoney(g.total)}</td></tr>`;
    }
    h += `<tr style=\"background:#f8f8f8; font-weight:bold;\"><td colspan=\"2\" style=\"padding:8px;\">TOTAL</td><td style=\"padding:8px; text-align:right; color:#e74c3c;\">${fmtMoney(totalArr(lista))}</td></tr>`;
    h += `</table>`;
  }
  h += `</div>`;
  return h;
};

// Helper: tabela receber consolidada por cliente
const tabelaReceberConsolidada = (lista, corTitulo, titulo) => {
  let h = `<div style=\"padding: 15px;\">`;
  h += `<h2 style=\"color: ${corTitulo}; font-size: 16px; border-bottom: 2px solid ${corTitulo}; padding-bottom: 5px;\">📥 ${titulo}</h2>`;
  if (lista.length === 0) {
    h += `<p style=\"color: #888;\">Nenhum registro.</p>`;
  } else {
    const grupos = {};
    for (const d of lista) {
      const nome = d.clienteNomeAbreviado || d.clienteNome;
      if (!grupos[nome]) grupos[nome] = { nfs: new Set(), total: 0, items: [] };
      grupos[nome].nfs.add(d.nfNumero);
      grupos[nome].total += d.dupValor;
      grupos[nome].items.push(d);
    }
    const sorted = Object.entries(grupos).sort((a,b) => b[1].total - a[1].total);
    h += `<table style=\"width:100%; border-collapse: collapse; font-size: 13px;\">`;
    h += `<tr style=\"background: #f8f8f8;\"><th style=\"padding:8px; text-align:left; border-bottom:2px solid #ddd;\">Cliente</th><th style=\"padding:8px; text-align:center; border-bottom:2px solid #ddd;\">NFs</th><th style=\"padding:8px; text-align:right; border-bottom:2px solid #ddd;\">Total</th></tr>`;
    for (const [nome, g] of sorted) {
      const nfList = Array.from(g.nfs).join(', ');
      h += `<tr><td style=\"padding:6px 8px; border-bottom:1px solid #eee;\">${nome}<br><span style=\"font-size:11px; color:#888;\">(NFs: ${nfList})</span></td><td style=\"padding:6px 8px; border-bottom:1px solid #eee; text-align:center;\">${g.nfs.size}</td><td style=\"padding:6px 8px; border-bottom:1px solid #eee; text-align:right; font-weight:bold;\">${fmtMoney(g.total)}</td></tr>`;
    }
    h += `<tr style=\"background:#f8f8f8; font-weight:bold;\"><td colspan=\"2\" style=\"padding:8px;\">TOTAL</td><td style=\"padding:8px; text-align:right; color:#27ae60;\">${fmtMoney(totalArr(lista))}</td></tr>`;
    h += `</table>`;
  }
  h += `</div>`;
  return h;
};

// Helper: tabela pagar semanal com divisórias por dia
const diasSemana = ['Domingo','Segunda-feira','Terça-feira','Quarta-feira','Quinta-feira','Sexta-feira','Sábado'];
const tabelaPagarSemanal = (lista, corTitulo, titulo, seg) => {
  let h = `<div style=\"padding: 15px;\">`;
  h += `<h2 style=\"color: ${corTitulo}; font-size: 16px; border-bottom: 2px solid ${corTitulo}; padding-bottom: 5px;\">💰 ${titulo}</h2>`;
  if (lista.length === 0) {
    h += `<p style=\"color: #888;\">Nenhum vencimento nesta semana.</p>`;
  } else {
    h += `<table style=\"width:100%; border-collapse: collapse; font-size: 13px;\">`;
    h += `<tr style=\"background: #f8f8f8;\"><th style=\"padding:8px; text-align:center; border-bottom:2px solid #ddd;\">Venc.</th><th style=\"padding:8px; text-align:left; border-bottom:2px solid #ddd;\">Fornecedor</th><th style=\"padding:8px; text-align:left; border-bottom:2px solid #ddd;\">NF</th><th style=\"padding:8px; text-align:center; border-bottom:2px solid #ddd;\">Parcela</th><th style=\"padding:8px; text-align:right; border-bottom:2px solid #ddd;\">Valor</th></tr>`;
    const diasAgrupados = [[1],[2],[3],[4],[5],[6,0]];
    const labelsGrupo = ['Segunda-feira','Terça-feira','Quarta-feira','Quinta-feira','Sexta-feira','Sáb/Dom → Segunda'];
    for (let g = 0; g < diasAgrupados.length; g++) {
      const diasDoGrupo = [];
      for (const dow of diasAgrupados[g]) {
        const offset = dow === 0 ? 6 : dow - 1;
        const dia = new Date(seg);
        dia.setDate(seg.getDate() + offset);
        const diaStr = `${dia.getFullYear()}-${pad2(dia.getMonth()+1)}-${pad2(dia.getDate())}`;
        diasDoGrupo.push(diaStr);
      }
      const doDia = lista.filter(d => diasDoGrupo.includes(d.dupVencimento));
      if (doDia.length === 0) continue;
      const labelDatas = g === 5 ? fmtDate((() => { const proxSeg = new Date(seg); proxSeg.setDate(seg.getDate() + 7); return `${proxSeg.getFullYear()}-${pad2(proxSeg.getMonth()+1)}-${pad2(proxSeg.getDate())}`; })()) : diasDoGrupo.map(ds => fmtDate(ds)).join(' e ');
      h += `<tr><td colspan=\"5\" style=\"padding:8px 8px 4px; background:#eef2f7; font-weight:bold; color:#2c3e50; font-size:12px; border-bottom:1px solid #ddd;\">📌 ${labelsGrupo[g]} — ${labelDatas}</td></tr>`;
      for (const d of doDia) {
        const sc = d.status === 'overdue' ? '#e74c3c' : d.status === 'due_today' ? '#f39c12' : '#333';
        h += `<tr><td style=\"padding:6px 8px; border-bottom:1px solid #eee; text-align:center;\">${fmtDate(d.dupVencimento)}</td><td style=\"padding:6px 8px; border-bottom:1px solid #eee; color:${sc};\">${d.emitenteNomeAbreviado || d.emitenteNome}</td><td style=\"padding:6px 8px; border-bottom:1px solid #eee;\">${d.nfNumero}</td><td style=\"padding:6px 8px; border-bottom:1px solid #eee; text-align:center;\">${fmtParcela(d.dupNumero, d.parcelaTotal)}</td><td style=\"padding:6px 8px; border-bottom:1px solid #eee; text-align:right; font-weight:bold;\">${fmtMoney(d.dupValor)}</td></tr>`;
      }
    }
    h += `<tr style=\"background:#f8f8f8; font-weight:bold;\"><td colspan=\"4\" style=\"padding:8px;\">TOTAL</td><td style=\"padding:8px; text-align:right; color:#e74c3c;\">${fmtMoney(totalArr(lista))}</td></tr>`;
    h += `</table>`;
  }
  h += `</div>`;
  return h;
};

// Helper: tabela receber semanal com divisórias por dia
const tabelaReceberSemanal = (lista, corTitulo, titulo, seg) => {
  let h = `<div style=\"padding: 15px;\">`;
  h += `<h2 style=\"color: ${corTitulo}; font-size: 16px; border-bottom: 2px solid ${corTitulo}; padding-bottom: 5px;\">📥 ${titulo}</h2>`;
  if (lista.length === 0) {
    h += `<p style=\"color: #888;\">Nenhum recebimento nesta semana.</p>`;
  } else {
    h += `<table style=\"width:100%; border-collapse: collapse; font-size: 13px;\">`;
    h += `<tr style=\"background: #f8f8f8;\"><th style=\"padding:8px; text-align:center; border-bottom:2px solid #ddd;\">Venc.</th><th style=\"padding:8px; text-align:left; border-bottom:2px solid #ddd;\">Cliente</th><th style=\"padding:8px; text-align:left; border-bottom:2px solid #ddd;\">NF</th><th style=\"padding:8px; text-align:center; border-bottom:2px solid #ddd;\">Parcela</th><th style=\"padding:8px; text-align:right; border-bottom:2px solid #ddd;\">Valor</th></tr>`;
    const diasAgrupados2 = [[1],[2],[3],[4],[5],[6,0]];
    const labelsGrupo2 = ['Segunda-feira','Terça-feira','Quarta-feira','Quinta-feira','Sexta-feira','Sáb/Dom → Segunda'];
    for (let g = 0; g < diasAgrupados2.length; g++) {
      const diasDoGrupo = [];
      for (const dow of diasAgrupados2[g]) {
        const offset = dow === 0 ? 6 : dow - 1;
        const dia = new Date(seg);
        dia.setDate(seg.getDate() + offset);
        const diaStr = `${dia.getFullYear()}-${pad2(dia.getMonth()+1)}-${pad2(dia.getDate())}`;
        diasDoGrupo.push(diaStr);
      }
      const doDia = lista.filter(d => diasDoGrupo.includes(d.dupVencimento));
      if (doDia.length === 0) continue;
      const labelDatas = g === 5 ? fmtDate((() => { const proxSeg = new Date(seg); proxSeg.setDate(seg.getDate() + 7); return `${proxSeg.getFullYear()}-${pad2(proxSeg.getMonth()+1)}-${pad2(proxSeg.getDate())}`; })()) : diasDoGrupo.map(ds => fmtDate(ds)).join(' e ');
      h += `<tr><td colspan=\"5\" style=\"padding:8px 8px 4px; background:#eaf5ee; font-weight:bold; color:#1a5e2a; font-size:12px; border-bottom:1px solid #ddd;\">📌 ${labelsGrupo2[g]} — ${labelDatas}</td></tr>`;
      for (const d of doDia) {
        h += `<tr><td style=\"padding:6px 8px; border-bottom:1px solid #eee; text-align:center;\">${fmtDate(d.dupVencimento)}</td><td style=\"padding:6px 8px; border-bottom:1px solid #eee;\">${d.clienteNomeAbreviado || d.clienteNome}</td><td style=\"padding:6px 8px; border-bottom:1px solid #eee;\">${d.nfNumero}</td><td style=\"padding:6px 8px; border-bottom:1px solid #eee; text-align:center;\">${fmtParcela(d.dupNumero, d.parcelaTotal)}</td><td style=\"padding:6px 8px; border-bottom:1px solid #eee; text-align:right; font-weight:bold;\">${fmtMoney(d.dupValor)}</td></tr>`;
      }
    }
    h += `<tr style=\"background:#f8f8f8; font-weight:bold;\"><td colspan=\"4\" style=\"padding:8px;\">TOTAL</td><td style=\"padding:8px; text-align:right; color:#27ae60;\">${fmtMoney(totalArr(lista))}</td></tr>`;
    h += `</table>`;
  }
  h += `</div>`;
  return h;
};

// Helper: tabela pagar
const tabelaPagar = (lista, corTitulo, titulo) => {
  let h = `<div style=\"padding: 15px;\">`;
  h += `<h2 style=\"color: ${corTitulo}; font-size: 16px; border-bottom: 2px solid ${corTitulo}; padding-bottom: 5px;\">💰 ${titulo}</h2>`;
  if (lista.length === 0) {
    h += `<p style=\"color: #888;\">Nenhum registro.</p>`;
  } else {
    h += `<table style=\"width:100%; border-collapse: collapse; font-size: 13px;\">`;
    h += `<tr style=\"background: #f8f8f8;\"><th style=\"padding:8px; text-align:center; border-bottom:2px solid #ddd;\">Venc.</th><th style=\"padding:8px; text-align:left; border-bottom:2px solid #ddd;\">Fornecedor</th><th style=\"padding:8px; text-align:left; border-bottom:2px solid #ddd;\">NF</th><th style=\"padding:8px; text-align:center; border-bottom:2px solid #ddd;\">Parcela</th><th style=\"padding:8px; text-align:right; border-bottom:2px solid #ddd;\">Valor</th></tr>`;
    for (const d of lista) {
      const sc = d.status === 'overdue' ? '#e74c3c' : d.status === 'due_today' ? '#f39c12' : '#333';
      h += `<tr><td style=\"padding:6px 8px; border-bottom:1px solid #eee; text-align:center;\">${fmtDate(d.dupVencimento)}</td><td style=\"padding:6px 8px; border-bottom:1px solid #eee; color:${sc};\">${d.emitenteNomeAbreviado || d.emitenteNome}</td><td style=\"padding:6px 8px; border-bottom:1px solid #eee;\">${d.nfNumero}</td><td style=\"padding:6px 8px; border-bottom:1px solid #eee; text-align:center;\">${fmtParcela(d.dupNumero, d.parcelaTotal)}</td><td style=\"padding:6px 8px; border-bottom:1px solid #eee; text-align:right; font-weight:bold;\">${fmtMoney(d.dupValor)}</td></tr>`;
    }
    h += `<tr style=\"background:#f8f8f8; font-weight:bold;\"><td colspan=\"4\" style=\"padding:8px;\">TOTAL</td><td style=\"padding:8px; text-align:right; color:#e74c3c;\">${fmtMoney(totalArr(lista))}</td></tr>`;
    h += `</table>`;
  }
  h += `</div>`;
  return h;
};

// Helper: tabela receber
const tabelaReceber = (lista, corTitulo, titulo) => {
  let h = `<div style=\"padding: 15px;\">`;
  h += `<h2 style=\"color: ${corTitulo}; font-size: 16px; border-bottom: 2px solid ${corTitulo}; padding-bottom: 5px;\">📥 ${titulo}</h2>`;
  if (lista.length === 0) {
    h += `<p style=\"color: #888;\">Nenhum registro.</p>`;
  } else {
    h += `<table style=\"width:100%; border-collapse: collapse; font-size: 13px;\">`;
    h += `<tr style=\"background: #f8f8f8;\"><th style=\"padding:8px; text-align:center; border-bottom:2px solid #ddd;\">Venc.</th><th style=\"padding:8px; text-align:left; border-bottom:2px solid #ddd;\">Cliente</th><th style=\"padding:8px; text-align:left; border-bottom:2px solid #ddd;\">NF</th><th style=\"padding:8px; text-align:center; border-bottom:2px solid #ddd;\">Parcela</th><th style=\"padding:8px; text-align:right; border-bottom:2px solid #ddd;\">Valor</th></tr>`;
    for (const d of lista) {
      h += `<tr><td style=\"padding:6px 8px; border-bottom:1px solid #eee; text-align:center;\">${fmtDate(d.dupVencimento)}</td><td style=\"padding:6px 8px; border-bottom:1px solid #eee;\">${d.clienteNomeAbreviado || d.clienteNome}</td><td style=\"padding:6px 8px; border-bottom:1px solid #eee;\">${d.nfNumero}</td><td style=\"padding:6px 8px; border-bottom:1px solid #eee; text-align:center;\">${fmtParcela(d.dupNumero, d.parcelaTotal)}</td><td style=\"padding:6px 8px; border-bottom:1px solid #eee; text-align:right; font-weight:bold;\">${fmtMoney(d.dupValor)}</td></tr>`;
    }
    h += `<tr style=\"background:#f8f8f8; font-weight:bold;\"><td colspan=\"4\" style=\"padding:8px;\">TOTAL</td><td style=\"padding:8px; text-align:right; color:#27ae60;\">${fmtMoney(totalArr(lista))}</td></tr>`;
    h += `</table>`;
  }
  h += `</div>`;
  return h;
};

// Helper: section header
const sectionHeader = (titulo, cor) => {
  return `<div style=\"background: ${cor}; color: white; padding: 12px 20px; margin-top: 10px;\"><h2 style=\"margin:0; font-size: 18px;\">${titulo}</h2></div>`;
};

// Helper: summary cards
const summaryCards = (pagarLista, receberLista, labelPagar, labelReceber) => {
  let h = `<div style=\"display: flex; gap: 10px; padding: 15px; background: #f5f5f5;\">`;
  h += `<div style=\"flex:1; background: white; padding: 12px; border-radius: 6px; border-left: 4px solid #e74c3c;\">`;
  h += `<div style=\"font-size: 12px; color: #888;\">${labelPagar}</div>`;
  h += `<div style=\"font-size: 20px; font-weight: bold; color: #e74c3c;\">${fmtMoney(totalArr(pagarLista))}</div>`;
  h += `<div style=\"font-size: 12px; color: #888;\">${pagarLista.length} título(s)</div></div>`;
  h += `<div style=\"flex:1; background: white; padding: 12px; border-radius: 6px; border-left: 4px solid #27ae60;\">`;
  h += `<div style=\"font-size: 12px; color: #888;\">${labelReceber}</div>`;
  h += `<div style=\"font-size: 20px; font-weight: bold; color: #27ae60;\">${fmtMoney(totalArr(receberLista))}</div>`;
  h += `<div style=\"font-size: 12px; color: #888;\">${receberLista.length} título(s)</div></div>`;
  h += `</div>`;
  return h;
};

let html = `<div style=\"font-family: Arial, sans-serif; max-width: 800px; margin: 0 auto;\">`;

// === HEADER ===
html += `<div style=\"background: #1e3a5f; color: white; padding: 20px; border-radius: 8px 8px 0 0;\">`;
html += `<h1 style=\"margin:0; font-size: 22px;\">📊 Contas a Pagar/Receber</h1>`;
html += `<p style=\"margin: 5px 0 0; opacity: 0.8;\">Semana ${fmtDateRange(seg)} a ${fmtDateRange(dom)}</p>`;
html += `</div>`;

// === AVISO EXPERIMENTAL ===
html += `<div style=\"background: #fff3cd; border-left: 4px solid #ffc107; padding: 10px 15px; margin: 0;\"><strong style=\"color: #856404;\">⚠️ Relatório experimental</strong><span style=\"color: #856404;\"> — Este relatório é gerado automaticamente e pode conter erros. Confira os dados no painel antes de tomar decisões.</span></div>`;

// === SEMANAL ===
html += sectionHeader('📅 Esta Semana', '#2c3e50');
html += summaryCards(pagarSemana, receberSemana, 'A PAGAR ESTA SEMANA', 'A RECEBER ESTA SEMANA');
if (vencidas.length > 0) {
  html += `<div style=\"padding: 0 15px;\"><div style=\"background: #fdf0f0; border-left: 4px solid #c0392b; padding: 10px 12px; margin-top: 5px; border-radius: 4px;\"><strong style=\"color: #c0392b;\">⚠️ ${vencidas.length} título(s) vencido(s)</strong> — Total: <strong>${fmtMoney(totalArr(vencidas))}</strong></div></div>`;
}
html += tabelaPagarSemanal(pagarSemana, '#e74c3c', 'Contas a Pagar — Esta Semana', seg);
html += tabelaReceberSemanal(receberSemana, '#27ae60', 'Contas a Receber — Esta Semana', seg);

// === MÊS ATUAL ===
html += sectionHeader(`📆 Relatório Contas a Pagar/Receber — ${nomeMesAtual.charAt(0).toUpperCase() + nomeMesAtual.slice(1)}`, '#1a5276');
html += summaryCards(pagarMesAtual, receberMesAtual, `A PAGAR EM ${nomeMesAtual.toUpperCase()}`, `A RECEBER EM ${nomeMesAtual.toUpperCase()}`);
html += tabelaPagarConsolidada(pagarMesAtual, '#e74c3c', `Contas a Pagar — ${nomeMesAtual.charAt(0).toUpperCase() + nomeMesAtual.slice(1)}`);
html += tabelaReceberConsolidada(receberMesAtual, '#27ae60', `Contas a Receber — ${nomeMesAtual.charAt(0).toUpperCase() + nomeMesAtual.slice(1)}`);

// === PRÓXIMO MÊS ===
html += sectionHeader(`📆 Relatório Contas a Pagar/Receber — ${nomeProxMes.charAt(0).toUpperCase() + nomeProxMes.slice(1)}`, '#7d3c98');
html += summaryCards(pagarProxMes, receberProxMes, `A PAGAR EM ${nomeProxMes.toUpperCase()}`, `A RECEBER EM ${nomeProxMes.toUpperCase()}`);
html += tabelaPagarConsolidada(pagarProxMes, '#e74c3c', `Contas a Pagar — ${nomeProxMes.charAt(0).toUpperCase() + nomeProxMes.slice(1)}`);
html += tabelaReceberConsolidada(receberProxMes, '#27ae60', `Contas a Receber — ${nomeProxMes.charAt(0).toUpperCase() + nomeProxMes.slice(1)}`);

// === CONSOLIDADO ANO ATUAL ===
const anoAtual = hoje.getFullYear();
const anoAtualIni = `${anoAtual}-01-01`;
const anoAtualFim = `${anoAtual}-12-31`;
const proxAno = anoAtual + 1;
const proxAnoIni = `${proxAno}-01-01`;
const proxAnoFim = `${proxAno}-12-31`;

const meses = ['Janeiro','Fevereiro','Março','Abril','Maio','Junho','Julho','Agosto','Setembro','Outubro','Novembro','Dezembro'];

const consolidadoTotal = (allP, allR, anoIni, anoFim, ano) => {
  const pAno = allP.filter(d => d.dupVencimento >= anoIni && d.dupVencimento <= anoFim);
  const rAno = allR.filter(d => d.dupVencimento >= anoIni && d.dupVencimento <= anoFim);
  const vp = totalArr(pAno);
  const vr = totalArr(rAno);
  const saldo = vr - vp;
  const saldoCor = saldo >= 0 ? '#27ae60' : '#e74c3c';
  let h = `<div style=\"display: flex; gap: 10px; padding: 15px; background: #f5f5f5;\">`;
  h += `<div style=\"flex:1; background: white; padding: 12px; border-radius: 6px; border-left: 4px solid #e74c3c;\">`;
  h += `<div style=\"font-size: 12px; color: #888;\">TOTAL A PAGAR ${ano}</div>`;
  h += `<div style=\"font-size: 20px; font-weight: bold; color: #e74c3c;\">${fmtMoney(vp)}</div>`;
  h += `<div style=\"font-size: 12px; color: #888;\">${pAno.length} título(s)</div></div>`;
  h += `<div style=\"flex:1; background: white; padding: 12px; border-radius: 6px; border-left: 4px solid #27ae60;\">`;
  h += `<div style=\"font-size: 12px; color: #888;\">TOTAL A RECEBER ${ano}</div>`;
  h += `<div style=\"font-size: 20px; font-weight: bold; color: #27ae60;\">${fmtMoney(vr)}</div>`;
  h += `<div style=\"font-size: 12px; color: #888;\">${rAno.length} título(s)</div></div>`;
  h += `<div style=\"flex:1; background: white; padding: 12px; border-radius: 6px; border-left: 4px solid ${saldoCor};\">`;
  h += `<div style=\"font-size: 12px; color: #888;\">SALDO ${ano}</div>`;
  h += `<div style=\"font-size: 20px; font-weight: bold; color: ${saldoCor};\">${fmtMoney(saldo)}</div>`;
  h += `<div style=\"font-size: 12px; color: #888;\">${saldo >= 0 ? 'Positivo' : 'Negativo'}</div></div>`;
  h += `</div>`;
  return h;
};

html += sectionHeader(`📊 Consolidado ${anoAtual}`, '#0b5345');
html += consolidadoTotal(allPagar, allReceber, anoAtualIni, anoAtualFim, anoAtual);

html += sectionHeader(`📊 Consolidado ${proxAno}`, '#4a235a');
html += consolidadoTotal(allPagar, allReceber, proxAnoIni, proxAnoFim, proxAno);

// === FOOTER ===
html += `<div style=\"padding: 15px; background: #f5f5f5; border-radius: 0 0 8px 8px; text-align: center; font-size: 12px; color: #888;\">`;
html += `Gerado automaticamente pelo QLMED em ${new Date().toLocaleString('pt-BR', {timeZone: 'America/Sao_Paulo'})}`;
html += ` | <a href=\"https://app.qlmed.com.br/dashboard/contas-pagar\" style=\"color: #1e3a5f;\">Ver no painel</a>`;
html += `</div></div>`;

const subject = `Contas a Pagar/Receber Semanal (${fmtDateRange(seg)} a ${fmtDateRange(dom)})`;

return [{ json: { subject, html } }];
